class SecurityLogger {
  static LOG_QUEUE = [];
  static FLUSH_INTERVAL = 30000;

  static async log(event, data = {}) {
    const logEntry = {
      event,
      data: this._sanitize(data),
      timestamp: new Date().toISOString(),
      platform: Platform.OS,
      appVersion: DeviceInfo.getVersion(),
      deviceId: await DeviceInfo.getUniqueId(),
      sessionId: PaymentSession.currentSessionId,
    };

    this.LOG_QUEUE.push(logEntry);

    if (__DEV__) {
      console.log('[SecurityLog]', JSON.stringify(logEntry));
    }

    // Flush critical events immediately
    const criticalEvents = [
      'PAYMENT_FRAUD_DETECTED',
      'INTEGRITY_CRITICAL',
      'TAMPER_DETECTED',
      'UNAUTHORIZED_ACCESS',
    ];
    if (criticalEvents.includes(event)) {
      await this.flush();
    }
  }

  static _sanitize(data) {
    const sensitiveKeys = ['cardNumber', 'cvv', 'pin', 'password', 'token', 'privateKey'];
    const sanitized = { ...data };
    for (const key of sensitiveKeys) {
      if (sanitized[key]) {
        sanitized[key] = '[REDACTED]';
      }
    }
    return sanitized;
  }

  static async flush() {
    if (this.LOG_QUEUE.length === 0) return;
    const batch = [...this.LOG_QUEUE];
    this.LOG_QUEUE = [];
    try {
      await SecureApiClient.post('/api/v1/security-logs', { logs: batch });
    } catch {
      // Re-queue on failure
      this.LOG_QUEUE = [...batch, ...this.LOG_QUEUE];
    }
  }
}

