// Secure API Client with SSL Pinning
// ============================================================
class SecureApiClient {
  static BASE_URL = 'https://api.payment-provider.com';
  static TIMEOUT = 30000;

  static SSL_PINS = {
    'api.payment-provider.com': [
      'sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=',
      'sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=',
    ],
  };

  static async request(method, endpoint, data = null, headers = {}) {
    const url = `${this.BASE_URL}${endpoint}`;
    const requestId = CryptoJS.lib.WordArray.random(16).toString();

    const defaultHeaders = {
      'Content-Type': 'application/json',
      'X-Request-ID': requestId,
      'X-Platform': Platform.OS,
      'X-App-Version': DeviceInfo.getVersion(),
      'X-Device-ID': await DeviceInfo.getUniqueId(),
      ...headers,
    };

    // Add session token if available
    const sessionToken = await PaymentSession.getSessionToken();
    if (sessionToken) {
      defaultHeaders['Authorization'] = `Bearer ${sessionToken}`;
    }

    try {
      const response = await RNSSLPinning.fetch(url, {
        method,
        headers: defaultHeaders,
        body: data ? JSON.stringify(data) : undefined,
        sslPinning: {
          certs: ['payment_provider_cert'],
        },
        timeoutInterval: this.TIMEOUT,
      });

      const responseData = await response.json();

      if (response.status >= 400) {
        throw new PaymentError(
          responseData.message || 'API request failed',
          responseData.code || 'API_ERROR',
          response.status
        );
      }

      return { data: responseData, status: response.status, requestId };
    } catch (error) {
      if (error instanceof PaymentError) throw error;

      SecurityLogger.log('API_REQUEST_FAILED', {
        endpoint,
        error: error.message,
        requestId,
      });

      throw new PaymentError(
        'Network request failed',
        'NETWORK_ERROR',
        0
      );
    }
  }

  static get(endpoint, headers = {}) {
    return this.request('GET', endpoint, null, headers);
  }

  static post(endpoint, data, headers = {}) {
    return this.request('POST', endpoint, data, headers);
  }

  static put(endpoint, data, headers = {}) {
    return this.request('PUT', endpoint, data, headers);
  }
}

