// Secure Storage Service
// ============================================================
class SecureStorageService {
  static ENCRYPTION_KEY_ALIAS = 'payment_module_enc_key';

  static async store(key, value) {
    try {
      const encrypted = await this._encrypt(JSON.stringify(value));
      if (NativeModules.SecureKeystore) {
        await NativeModules.SecureKeystore.set(key, encrypted);
      } else {
        // Fallback with encrypted AsyncStorage
        await AsyncStorage.setItem(`@secure_${key}`, encrypted);
      }
    } catch (error) {
      SecurityLogger.log('SECURE_STORAGE_WRITE_ERROR', { key, error: error.message });
      throw new PaymentError('Failed to store secure data', 'STORAGE_ERROR');
    }
  }

  static async retrieve(key) {
    try {
      let encrypted;
      if (NativeModules.SecureKeystore) {
        encrypted = await NativeModules.SecureKeystore.get(key);
      } else {
        encrypted = await AsyncStorage.getItem(`@secure_${key}`);
      }

      if (!encrypted) return null;

      const decrypted = await this._decrypt(encrypted);
      return JSON.parse(decrypted);
    } catch (error) {
      SecurityLogger.log('SECURE_STORAGE_READ_ERROR', { key, error: error.message });
      return null;
    }
  }

  static async remove(key) {
    try {
      if (NativeModules.SecureKeystore) {
        await NativeModules.SecureKeystore.remove(key);
      } else {
        await AsyncStorage.removeItem(`@secure_${key}`);
      }
    } catch (error) {
      SecurityLogger.log('SECURE_STORAGE_DELETE_ERROR', { key, error: error.message });
    }
  }

  static async _encrypt(plaintext) {
    const key = await this._getOrCreateEncryptionKey();
    const iv = CryptoJS.lib.WordArray.random(16);
    const encrypted = CryptoJS.AES.encrypt(plaintext, key, {
      iv,
      mode: CryptoJS.mode.CBC,
      padding: CryptoJS.pad.Pkcs7,
    });
    return iv.toString() + ':' + encrypted.toString();
  }

  static async _decrypt(ciphertext) {
    const key = await this._getOrCreateEncryptionKey();
    const parts = ciphertext.split(':');
    const iv = CryptoJS.enc.Hex.parse(parts[0]);
    const encrypted = parts[1];
    const decrypted = CryptoJS.AES.decrypt(encrypted, key, {
      iv,
      mode: CryptoJS.mode.CBC,
      padding: CryptoJS.pad.Pkcs7,
    });
    return decrypted.toString(CryptoJS.enc.Utf8);
  }

  static async _getOrCreateEncryptionKey() {
    if (NativeModules.SecureKeystore) {
      let key = await NativeModules.SecureKeystore.get(this.ENCRYPTION_KEY_ALIAS);
      if (!key) {
        key = CryptoJS.lib.WordArray.random(32).toString();
        await NativeModules.SecureKeystore.set(this.ENCRYPTION_KEY_ALIAS, key);
      }
      return CryptoJS.enc.Hex.parse(key);
    }
    // Derive key from device-specific data as fallback
    const deviceId = await DeviceInfo.getUniqueId();
    return CryptoJS.PBKDF2(deviceId, 'payment_module_salt', {
      keySize: 256 / 32,
      iterations: 10000,
    });
  }
}

