class InAppPurchaseManager {
  static async initialize() {
    if (Platform.OS === 'ios') {
      return await this._initializeStoreKit();
    } else if (Platform.OS === 'android') {
      return await this._initializeGoogleBilling();
    }
    throw new PaymentError('Unsupported platform', 'PLATFORM_ERROR');
  }

  static async _initializeStoreKit() {
    if (!NativeModules.StoreKitBridge) {
      throw new PaymentError('StoreKit not available', 'IAP_UNAVAILABLE');
    }
    return await NativeModules.StoreKitBridge.initialize();
  }

  static async _initializeGoogleBilling() {
    if (!NativeModules.GoogleBillingBridge) {
      throw new PaymentError('Google Billing not available', 'IAP_UNAVAILABLE');
    }
    return await NativeModules.GoogleBillingBridge.initialize();
  }

  static async getProducts(productIds) {
    try {
      if (Platform.OS === 'ios') {
        return await NativeModules.StoreKitBridge.getProducts(productIds);
      } else {
        return await NativeModules.GoogleBillingBridge.getProducts(productIds);
      }
    } catch (error) {
      SecurityLogger.log('GET_PRODUCTS_FAILED', { error: error.message });
      throw new PaymentError('Failed to fetch products', 'PRODUCTS_ERROR');
    }
  }

  static async purchaseProduct(productId, integrityResult) {
    // Enforce integrity requirements for purchases
    if (integrityResult.riskLevel === DeviceIntegrityService.RISK_LEVEL.CRITICAL) {
      SecurityLogger.log('PURCHASE_BLOCKED_INTEGRITY', {
        productId,
        riskLevel: integrityResult.riskLevel,
        riskScore: integrityResult.riskScore,
      });
      throw new PaymentError(
        'Purchase cannot be completed on this device due to security concerns',
        'INTEGRITY_VIOLATION'
      );
    }

    try {
      let purchaseResult;

      if (Platform.OS === 'ios') {
        purchaseResult = await NativeModules.StoreKitBridge.purchaseProduct(productId);
      } else {
        purchaseResult = await NativeModules.GoogleBillingBridge.purchaseProduct(productId);
      }

      // Server-side receipt validation
      const validationResult = await this._validateReceipt(purchaseResult, integrityResult);

      if (!validationResult.valid) {
        SecurityLogger.log('RECEIPT_VALIDATION_FAILED', {
          productId,
          reason: validationResult.reason,
        });
        throw new PaymentError('Purchase validation failed', 'VALIDATION_ERROR');
      }

      SecurityLogger.log('PURCHASE_COMPLETED', {
        productId,
        transactionId: purchaseResult.transactionId,
        riskLevel: integrityResult.riskLevel,
      });

      return {
        success: true,
        transactionId: purchaseResult.transactionId,
        productId,
        receipt: purchaseResult.receipt,
      };
    } catch (error) {
      if (error instanceof PaymentError) throw error;
      SecurityLogger.log('PURCHASE_FAILED', { productId, error: error.message });
      throw new PaymentError('Purchase failed', 'PURCHASE_ERROR');
    }
  }

  static async _validateReceipt(purchaseResult, integrityResult) {
    const response = await SecureApiClient.post('/api/v1/validate-receipt', {
      receipt: purchaseResult.receipt,
      transactionId: purchaseResult.transactionId,
      productId: purchaseResult.productId,
      platform: Platform.OS,
      deviceIntegrity: {
        riskLevel: integrityResult.riskLevel,
        riskScore: integrityResult.riskScore,
        isRooted: integrityResult.isRooted,
        isEmulator: integrityResult.isEmulator,
      },
    });

    return response.data;
  }

  static async restorePurchases() {
    try {
      if (Platform.OS === 'ios') {
        return await NativeModules.StoreKitBridge.restorePurchases();
      } else {
        return await NativeModules.GoogleBillingBridge.restorePurchases();
      }
    } catch (error) {
      SecurityLogger.log('RESTORE_PURCHASES_FAILED', { error: error.message });
      throw new PaymentError('Failed to restore purchases', 'RESTORE_ERROR');
    }
  }
}

